-- =============================================================================
-- D-061 — Statický IFC slovník psetov: `ifc_property_definitions`
-- =============================================================================
-- Referenčné dáta (vzor `relationship_types`, D-051): definície ŠTANDARDNÝCH
-- psetov (Pset_/Qto_) z bSDD/psd šablón IFC4X3 cez `ifcopenshell` — význam
-- (description), dátový typ (PrimaryMeasureType), enum hodnoty a aplikovateľné
-- triedy. LLM grounding VÝZNAMU properties; čo v dátach reálne JE (vrátane
-- custom psetov), hovorí `v_property_dictionary` (D-058) — komplementárne.
--
-- Obsah je LEN pre triedy prítomné/plánované v projekte (kurátorovaný zoznam
-- v `etl/pset_manifest.py`), nie celý IFC4.3 katalóg. INSERTy sú generované:
--     python -m etl.pset_manifest --sql
-- Po zmene dát (nové triedy v DB) sa slovník regeneruje NOVOU migráciou
-- (`--classes-from-db`); tento súbor sa NEEDITUJE (aditívne migrácie).
--
-- Zápis do tabuľky robí len migrácia (referenčné dáta) — ETL ju nečíta ani
-- neplní. LLM ju dotazuje cez query_view (whitelist QUERY_RELATIONS).

begin;

create table ifc_property_definitions (
  pset                text not null,      -- 'Pset_DoorCommon'
  property            text not null,      -- 'FireRating'
  data_type           text,               -- PrimaryMeasureType: IfcLabel, IfcAreaMeasure…
  template_type       text,               -- P_SINGLEVALUE | P_ENUMERATEDVALUE | Q_*…
  enum_values         text[] not null default array[]::text[],  -- pri P_ENUMERATEDVALUE
  description         text,               -- orezané na 200 znakov (grounding, nie špec)
  applicable_classes  text[] not null,    -- triedy projektu, pre ktoré pset platí
  primary key (pset, property)
);

comment on table ifc_property_definitions is
  'D-061: statický slovník štandardných IFC psetov (generovaný etl/pset_manifest.py) — význam/typ/enum properties pre LLM grounding.';

insert into ifc_property_definitions
  (pset, property, data_type, template_type, enum_values, description, applicable_classes)
